import Foundation

struct WeatherEntry {
    let date: Date
    let temperature: Int
    let condition: String
}

func weatherTimeline() -> ([WeatherEntry], String) {
    let now = Date()
    let forecasts = [
        (72, "Sunny"), (70, "Partly Cloudy"),
        (68, "Cloudy"), (65, "Rain"
    )]
    let entries = forecasts.enumerated().map { (i, forecast) in
        WeatherEntry(
            date: now.addingTimeInterval(Double(i) * 3600),
            temperature: forecast.0,
            condition: forecast.1
        )
    }
    return (entries, "atEnd")
}

let (entries, policy) = weatherTimeline()
print("Entries: \(entries.count), Policy: \(policy)")

