sections.solution:
import Foundation

struct CityConfig {
    let cityName: String
}

struct Forecast {
    let city: String
    let temp: Int
}

func fetchForecast(for config: CityConfig) -> Forecast {
    let temps: [String: Int] = [
        "San Francisco": 64, "New York": 78, "London": 62
    ]
    let temp = temps[config.cityName] ?? 70
    return Forecast(city: config.cityName, temp: temp)
}

let config = CityConfig(cityName: "San Francisco")
let forecast = fetchForecast(for: config)
print("\(forecast.city): \(forecast.temp)°F")
